// My Responses Pageclass MyResponsesPage { constructor() { this.responses = []; this.init(); } async init() { document.getElementById('logout-btn').addEventListener('click', () => { window.app.logout(); }); await this.loadMyResponses(); } async loadMyResponses() { const loading = document.getElementById('loading'); const errorMessage = document.getElementById('error-message'); const responsesContainer = document.getElementById('responses-container'); const responsesList = document.getElementById('responses-list'); try { loading.style.display = 'block'; errorMessage.style.display = 'none'; responsesContainer.style.display = 'none'; const responses = await window.app.apiRequest('/api/surveys/my'); this.responses = responses; loading.style.display = 'none'; responsesContainer.style.display = 'block'; if (!responses || responses.length === 0) { responsesList.innerHTML = '<div class="empty-state"><h2>Ответов пока нет</h2><p>Вы еще не прошли ни одного опроса.</p></div>'; return; } this.renderResponses(); } catch (error) { console.error('Error loading my responses:', error); loading.style.display = 'none'; errorMessage.style.display = 'block'; errorMessage.textContent = 'Ошибка загрузки ответов.'; } } renderResponses() { const responsesList = document.getElementById('responses-list'); responsesList.innerHTML = ''; this.responses.forEach(response => { const responseDiv = document.createElement('div'); responseDiv.className = 'response-card'; responseDiv.innerHTML = ` <div class="response-header"> <h3>${response.survey_title}</h3> <span class="response-date">${new Date(response.submitted_at).toLocaleDateString('ru-RU')}</span> </div> <div class="response-content"> <p>${response.survey_description || 'Без описания'}</p> <div class="response-actions"> <button onclick="window.location.href='/surveys/responses/${response.id}'" class="btn btn-secondary btn-sm">📝 Просмотреть мои ответы</button> <button onclick="window.location.href='/surveys/${response.survey_id}/results'" class="btn btn-secondary btn-sm">📊 Результаты опроса</button> </div> </div> `; responsesList.appendChild(responseDiv); }); }}// Initialize page when DOM is loadeddocument.addEventListener('DOMContentLoaded', () => { new MyResponsesPage();});